export async function deliver(hook, event) {
  const body = JSON.stringify(event);
  const sig = hmac(hook.secret, body);
  for (let attempt = 0; attempt < 5; attempt++) {
    const res = await fetch(hook.url, { method: 'POST', headers: { 'X-Signature': sig }, body });
    if (res.ok) return;
    await sleep(2 ** attempt * 1000);
  }
  await dlq.add({ hook: hook.id, event });
}
